// AccountServiceServer is the server API for AccountService service.
// All implementations must embed UnimplementedAccountServiceServer
// for forward compatibility.
//
// Account registry RPCs for BFFs (e.g. quant-handler); wallet RPCs for strategy-service.
type AccountServiceServer interface {
	// Create a user account (internal auth store for quant-handler).
	CreateUser(context.Context, *CreateUserRequest) (*CreateUserResponse, error)
	// Verify a user's password and return the matching user metadata.
	VerifyUserPassword(context.Context, *VerifyUserPasswordRequest) (*VerifyUserPasswordResponse, error)
	// GetUser fetches user metadata by id. Used by control-panel-service to
	// read users.plan_code during runtime quota / route resolution. Sensitive
	// fields (password_hash) are never returned.
	GetUser(context.Context, *GetUserRequest) (*GetUserResponse, error)
	// Create a trading account (same rules as HTTP POST /accounts).
	CreateAccount(context.Context, *CreateAccountRequest) (*CreateAccountResponse, error)
	// List accounts; credentials are never returned.
	ListAccounts(context.Context, *ListAccountsRequest) (*ListAccountsResponse, error)
	// Get one account by id; credentials are never returned.
	GetAccount(context.Context, *GetAccountRequest) (*GetAccountResponse, error)
	CreateVenue(context.Context, *CreateVenueRequest) (*CreateVenueResponse, error)
	ListVenues(context.Context, *ListVenuesRequest) (*ListVenuesResponse, error)
	GetVenue(context.Context, *GetVenueRequest) (*GetVenueResponse, error)
	GetVenueOnlineInfo(context.Context, *GetVenueOnlineInfoRequest) (*GetVenueOnlineInfoResponse, error)
	BindVenue(context.Context, *BindVenueRequest) (*BindVenueResponse, error)
	ReleaseVenue(context.Context, *ReleaseVenueRequest) (*ReleaseVenueResponse, error)
	ArchiveVenue(context.Context, *ArchiveVenueRequest) (*ArchiveVenueResponse, error)
	PreflightStrategySession(context.Context, *PreflightStrategySessionRequest) (*PreflightStrategySessionResponse, error)
	GetVenueRouteMeta(context.Context, *GetVenueRouteMetaRequest) (*GetVenueRouteMetaResponse, error)
	// Phase 2 canonical portfolio snapshot API. It reads active account venues
	// through the exchange capability registry and returns account-level summary
	// plus per-venue balances/positions.
	GetPortfolioSnapshot(context.Context, *GetPortfolioSnapshotRequest) (*GetPortfolioSnapshotResponse, error)
	// Refresh and persist the current portfolio snapshot. Exchange-backed
	// accounts read from active venues; backtest accounts read local state.
	UpdatePortfolioSnapshot(context.Context, *UpdatePortfolioSnapshotRequest) (*UpdatePortfolioSnapshotResponse, error)
	// Cached tradable symbols for portal pickers (Binance public exchangeInfo). market: "spot" | "usdm_futures".
	ListSymbols(context.Context, *ListSymbolsRequest) (*ListSymbolsResponse, error)
	// Internal RPC: returns full account config including API credentials.
	// Intended for the internal order module only; NOT exposed to BFFs/portals.
	GetAccountMeta(context.Context, *GetAccountMetaRequest) (*GetAccountMetaResponse, error)
	// 创建策略（immutable，创建后不可修改）
	CreateStrategy(context.Context, *CreateStrategyRequest) (*CreateStrategyResponse, error)
	// 列出所有策略（可选按名称过滤）
	ListStrategies(context.Context, *ListStrategiesRequest) (*ListStrategiesResponse, error)
	// 获取单个策略（含 code）
	GetStrategy(context.Context, *GetStrategyRequest) (*GetStrategyResponse, error)
	// 归档策略（软删除，不可挂载已归档策略）
	ArchiveStrategy(context.Context, *ArchiveStrategyRequest) (*ArchiveStrategyResponse, error)
	// 挂载策略到帐号
	MountStrategy(context.Context, *MountStrategyRequest) (*MountStrategyResponse, error)
	// 从帐号卸载策略
	UnmountStrategy(context.Context, *UnmountStrategyRequest) (*UnmountStrategyResponse, error)
	// 激活帐号上的某个已挂载策略（同时使其他策略变为非 active）
	ActivateStrategy(context.Context, *ActivateStrategyRequest) (*ActivateStrategyResponse, error)
	// 取消激活策略（不卸载，仅设为非 active）
	DeactivateStrategy(context.Context, *DeactivateStrategyRequest) (*DeactivateStrategyResponse, error)
	// 列出帐号上所有已挂载策略
	ListAccountStrategies(context.Context, *ListAccountStrategiesRequest) (*ListAccountStrategiesResponse, error)
	// 获取帐号当前 active 策略（strategy-service 调用）
	GetActiveStrategy(context.Context, *GetActiveStrategyRequest) (*GetActiveStrategyResponse, error)
	// 保存新 session（strategy-service 调用）
	SaveSession(context.Context, *SaveSessionRequest) (*SaveSessionResponse, error)
	// 更新 session 状态（completed/stopped/failed/recoverable）
	UpdateSession(context.Context, *UpdateSessionRequest) (*UpdateSessionResponse, error)
	// 获取单个 session
	GetSession(context.Context, *GetSessionRequest) (*GetSessionResponse, error)
	// 列出帐号的所有 sessions
	ListSessions(context.Context, *ListSessionsRequest) (*ListSessionsResponse, error)
	// 列出所有 running sessions（用于服务重启恢复）
	ListRunningSessions(context.Context, *ListRunningSessionsRequest) (*ListRunningSessionsResponse, error)
	// 将指定 runtime 拥有的 active sessions 标记为 recoverable。
	MarkRuntimeSessionsRecoverable(context.Context, *MarkRuntimeSessionsRecoverableRequest) (*MarkRuntimeSessionsRecoverableResponse, error)
	// 列出 session 关联的快照
	ListSessionSnapshots(context.Context, *ListSessionSnapshotsRequest) (*ListSessionSnapshotsResponse, error)
	// 列出 session 关联的 reconciliation compare runs（Phase C / C3 审计入口）
	ListReconciliationRuns(context.Context, *ListReconciliationRunsRequest) (*ListReconciliationRunsResponse, error)
	// session 维度的 reconciliation 聚合（总数 / hard fail / soft fail）。
	// SessionDetailPage 用它驱动顶部 tile，而不是依赖当前页计数。
	GetSessionReconciliationSummary(context.Context, *GetSessionReconciliationSummaryRequest) (*GetSessionReconciliationSummaryResponse, error)
	// 获取当前用户通知偏好、plan 权限、Telegram 绑定状态和 bot 用户名。
	GetNotificationSettings(context.Context, *GetNotificationSettingsRequest) (*GetNotificationSettingsResponse, error)
	// 更新当前用户通知偏好。Plan 禁用的类别仍可存储偏好，但发送时 fail-closed。
	UpdateNotificationPreferences(context.Context, *UpdateNotificationPreferencesRequest) (*UpdateNotificationPreferencesResponse, error)
	// 创建一次性 Telegram 绑定码。明文 bind_code 只在本响应中返回一次。
	CreateNotificationBindCode(context.Context, *CreateNotificationBindCodeRequest) (*CreateNotificationBindCodeResponse, error)
	// 用户在 Telegram 发送绑定码后，页面调用该 RPC 刷新/确认绑定状态。
	ConfirmNotificationBinding(context.Context, *ConfirmNotificationBindingRequest) (*ConfirmNotificationBindingResponse, error)
	// 解绑当前用户的 Telegram 通知接收端。
	UnbindNotificationChannel(context.Context, *UnbindNotificationChannelRequest) (*UnbindNotificationChannelResponse, error)
	// 发送测试通知。用于验证当前 plan、偏好和 Telegram 绑定是否有效。
	SendTestNotification(context.Context, *SendTestNotificationRequest) (*SendTestNotificationResponse, error)
	mustEmbedUnimplementedAccountServiceServer()
}

